args.sparql:
SELECT ?golfer ?golferLabel WHERE {
  ?show wdt:P31 wd:Q3344513;
        rdfs:label "삼시 세끼"@ko.

  ?show wdt:P361 ?season.
  ?season wdt:P582 ?endDate.
  ORDER BY DESC(?endDate)
  LIMIT 1

  ?season wdt:P1433 ?location.

  ?golfer wdt:P106 wd:Q262206;
          wdt:P19 ?location.
  ?golfer rdfs:label ?golferLabel.
  FILTER (LANG(?golferLabel) = 'en')
}

